from langchain.callbacks.base import BaseCallbackHandler
from presidio_analyzer import AnalyzerEngine
import re

class OutputSafetyFilter(BaseCallbackHandler):
    def __init__(self, block_on_detection=True):
        self.analyzer = AnalyzerEngine()
        self.block_on_detection = block_on_detection
        self.secret_patterns = {
            'api_key': re.compile(r'\b[A-Za-z0-9_-]{32,}\b'),
            'aws_key': re.compile(r'AKIA[0-9A-Z]{16}'),
        }

    def on_llm_end(self, response, **kwargs):
        for generation in response.generations:
            text = generation[0].text

            # Check for PII
            pii_results = self.analyzer.analyze(text, language='en', score_threshold=0.6)

            # Check for secrets
            for pattern in self.secret_patterns.values():
                if pattern.search(text):
                    if self.block_on_detection:
                        generation[0].text = "I cannot provide that information."
                    break
